#include <iostream>
#include <memory>

struct Item {
    int value;
    Item(int v) : value{v} {}
};

int main() {
    int value{};
    std::cin >> value;

    auto owner = std::make_shared<Item>(value);
    std::weak_ptr<Item> observer = owner;

    {
        auto locked = observer.lock();
        if (locked) {
            std::cout << "Observer lock: " << locked->value << "\n";
            std::cout << "Owner count: " << owner.use_count() << "\n";
        }
    }

    std::cout << "After unlock owner count: " << owner.use_count() << "\n";

    std::cout << std::boolalpha;
    std::cout << "Item alive: " << !observer.expired() << "\n";

    owner.reset();
    std::cout << "Item alive: " << !observer.expired() << "\n";

    return 0;
}
